import{_ as n,c as t,o as i,a1 as a}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Obsidian-Integration: Pläne automatisch speichern | plannotator","description":"Erfahren Sie, wie Sie die Obsidian-Integration von plannotator konfigurieren. Speichern Sie genehmigte Pläne automatisch in Ihrem Vault mit Frontmatter- und Tag-Generierung sowie benutzerdefinierten Speicherpfaden.","frontmatter":{"title":"Obsidian-Integration: Pläne automatisch speichern | plannotator","sidebarTitle":"Automatisch in Obsidian speichern","subtitle":"Obsidian-Integration: Pläne automatisch speichern | plannotator","description":"Erfahren Sie, wie Sie die Obsidian-Integration von plannotator konfigurieren. Speichern Sie genehmigte Pläne automatisch in Ihrem Vault mit Frontmatter- und Tag-Generierung sowie benutzerdefinierten Speicherpfaden.","tags":["plannotator","integration","obsidian","advanced"],"prerequisite":["start-getting-started"],"order":2},"headers":[],"relativePath":"de/backnotprop/plannotator/advanced/obsidian-integration/index.md","filePath":"de/backnotprop/plannotator/advanced/obsidian-integration/index.md"}'),r={name:"de/backnotprop/plannotator/advanced/obsidian-integration/index.md"};function s(o,e,l,d,h,c){return i(),t("div",null,[...e[0]||(e[0]=[a(`<h1 id="obsidian-integration-plane-automatisch-in-ihrer-notiz-bibliothek-speichern" tabindex="-1">Obsidian-Integration: Pläne automatisch in Ihrer Notiz-Bibliothek speichern <a class="header-anchor" href="#obsidian-integration-plane-automatisch-in-ihrer-notiz-bibliothek-speichern" aria-label="Permalink to &quot;Obsidian-Integration: Pläne automatisch in Ihrer Notiz-Bibliothek speichern&quot;">​</a></h1><h2 id="was-sie-lernen-werden" tabindex="-1">Was Sie lernen werden <a class="header-anchor" href="#was-sie-lernen-werden" aria-label="Permalink to &quot;Was Sie lernen werden&quot;">​</a></h2><ul><li>Genehmigte oder abgelehnte Pläne automatisch in Ihrem Obsidian Vault speichern</li><li>Die Mechanismen der Frontmatter- und Tag-Generierung verstehen</li><li>Speicherpfade und Ordner anpassen</li><li>Backlinks nutzen, um einen Wissensgraphen aufzubauen</li></ul><h2 id="das-problem" tabindex="-1">Das Problem <a class="header-anchor" href="#das-problem" aria-label="Permalink to &quot;Das Problem&quot;">​</a></h2><p>Sie überprüfen KI-generierte Pläne in Plannotator, aber nach der Genehmigung „verschwinden&quot; diese Pläne einfach. Sie möchten diese wertvollen Pläne in Obsidian speichern, um sie später nachschlagen und durchsuchen zu können – aber manuelles Kopieren und Einfügen ist mühsam und die Formatierung geht dabei verloren.</p><h2 id="wann-sie-diese-funktion-nutzen-sollten" tabindex="-1">Wann Sie diese Funktion nutzen sollten <a class="header-anchor" href="#wann-sie-diese-funktion-nutzen-sollten" aria-label="Permalink to &quot;Wann Sie diese Funktion nutzen sollten&quot;">​</a></h2><ul><li>Sie verwenden Obsidian als Wissensmanagement-Tool</li><li>Sie möchten KI-generierte Implementierungspläne langfristig speichern und überprüfen</li><li>Sie möchten die Graph-Ansicht und das Tag-System von Obsidian nutzen, um Ihre Pläne zu organisieren</li></ul><h2 id="das-konzept" tabindex="-1">Das Konzept <a class="header-anchor" href="#das-konzept" aria-label="Permalink to &quot;Das Konzept&quot;">​</a></h2><p>Die Obsidian-Integration von Plannotator speichert Planinhalte automatisch in Ihrem Obsidian Vault, wenn Sie einen Plan genehmigen oder ablehnen. Das System:</p><ol><li><strong>Erkennt Vaults</strong>: Liest automatisch alle Vaults aus der Obsidian-Konfigurationsdatei</li><li><strong>Generiert Frontmatter</strong>: Enthält Erstellungszeit, Quelle und Tags</li><li><strong>Extrahiert Tags</strong>: Extrahiert automatisch Tags aus Plantiteln und Codeblock-Sprachen</li><li><strong>Fügt Backlinks hinzu</strong>: Fügt einen <code>[[Plannotator Plans]]</code>-Link ein, um den Aufbau eines Wissensgraphen zu erleichtern</li></ol><div class="info custom-block"><p class="custom-block-title">Was ist Obsidian?</p><p>Obsidian ist eine Local-First-Notiz-App mit bidirektionalen Links, die das Markdown-Format unterstützt und Beziehungen zwischen Notizen über eine Graph-Ansicht visualisieren kann.</p></div><h2 id="🎒-voraussetzungen" tabindex="-1">🎒 Voraussetzungen <a class="header-anchor" href="#🎒-voraussetzungen" aria-label="Permalink to &quot;🎒 Voraussetzungen&quot;">​</a></h2><p>Stellen Sie sicher, dass Obsidian installiert und konfiguriert ist. Plannotator erkennt automatisch die Vaults auf Ihrem System, aber Sie benötigen mindestens einen Vault, um diese Funktion nutzen zu können.</p><h2 id="schritt-fur-schritt-anleitung" tabindex="-1">Schritt-für-Schritt-Anleitung <a class="header-anchor" href="#schritt-fur-schritt-anleitung" aria-label="Permalink to &quot;Schritt-für-Schritt-Anleitung&quot;">​</a></h2><h3 id="schritt-1-einstellungen-offnen" tabindex="-1">Schritt 1: Einstellungen öffnen <a class="header-anchor" href="#schritt-1-einstellungen-offnen" aria-label="Permalink to &quot;Schritt 1: Einstellungen öffnen&quot;">​</a></h3><p>Klicken Sie in der Plannotator-Oberfläche auf das Zahnrad-Symbol oben rechts, um das Einstellungsfenster zu öffnen.</p><p>Sie sollten den Einstellungsdialog mit mehreren Konfigurationsoptionen sehen.</p><h3 id="schritt-2-obsidian-integration-aktivieren" tabindex="-1">Schritt 2: Obsidian-Integration aktivieren <a class="header-anchor" href="#schritt-2-obsidian-integration-aktivieren" aria-label="Permalink to &quot;Schritt 2: Obsidian-Integration aktivieren&quot;">​</a></h3><p>Suchen Sie im Einstellungsfenster den Abschnitt „Obsidian Integration&quot; und klicken Sie auf den Schalter, um die Funktion zu aktivieren.</p><p>Nach der Aktivierung erkennt Plannotator automatisch die Obsidian Vaults auf Ihrem System.</p><p>Sie sollten im Dropdown-Menü die erkannten Vaults sehen (z.B. <code>My Vault</code>, <code>Work Notes</code>).</p><h3 id="schritt-3-vault-und-ordner-auswahlen" tabindex="-1">Schritt 3: Vault und Ordner auswählen <a class="header-anchor" href="#schritt-3-vault-und-ordner-auswahlen" aria-label="Permalink to &quot;Schritt 3: Vault und Ordner auswählen&quot;">​</a></h3><p>Wählen Sie aus dem Dropdown-Menü den Vault aus, in dem Sie Ihre Pläne speichern möchten. Falls kein Vault erkannt wird, können Sie:</p><ol><li>Die Option „Custom path...&quot; auswählen</li><li>Den vollständigen Pfad zum Vault in das Textfeld eingeben</li></ol><p>Geben Sie dann im Feld „Folder&quot; den Namen des Speicherordners ein (Standard ist <code>plannotator</code>).</p><p>Sie sollten unten eine Pfadvorschau sehen, die anzeigt, wo die Pläne gespeichert werden.</p><h3 id="schritt-4-plane-genehmigen-oder-ablehnen" tabindex="-1">Schritt 4: Pläne genehmigen oder ablehnen <a class="header-anchor" href="#schritt-4-plane-genehmigen-oder-ablehnen" aria-label="Permalink to &quot;Schritt 4: Pläne genehmigen oder ablehnen&quot;">​</a></h3><p>Nach Abschluss der Konfiguration können Sie KI-generierte Pläne wie gewohnt überprüfen. Wenn Sie auf „Approve&quot; oder „Send Feedback&quot; klicken, wird der Plan automatisch im konfigurierten Vault gespeichert.</p><p>Sie sollten in Obsidian eine neu erstellte Datei sehen, deren Dateiname das Format <code>Title - Jan 2, 2026 2-30pm.md</code> hat.</p><h3 id="schritt-5-gespeicherte-dateien-anzeigen" tabindex="-1">Schritt 5: Gespeicherte Dateien anzeigen <a class="header-anchor" href="#schritt-5-gespeicherte-dateien-anzeigen" aria-label="Permalink to &quot;Schritt 5: Gespeicherte Dateien anzeigen&quot;">​</a></h3><p>Öffnen Sie die gespeicherte Datei in Obsidian. Sie werden folgenden Inhalt sehen:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">created</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2026-01-24T14:30:00.000Z</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">source</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">plannotator</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">tags</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">plan</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">authentication</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">typescript</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">sql</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[[Plannotator Plans]]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Implementation Plan: User Authentication</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">...</span></span></code></pre></div><p>Beachten Sie das YAML-Frontmatter am Anfang der Datei, das Erstellungszeit, Quelle und Tags enthält.</p><h2 id="checkliste-✅" tabindex="-1">Checkliste ✅ <a class="header-anchor" href="#checkliste-✅" aria-label="Permalink to &quot;Checkliste ✅&quot;">​</a></h2><ul><li>[ ] Obsidian Integration ist im Einstellungsfenster aktiviert</li><li>[ ] Ein Vault wurde ausgewählt (oder ein benutzerdefinierter Pfad eingegeben)</li><li>[ ] Der Ordnername wurde festgelegt</li><li>[ ] Nach dem Genehmigen oder Ablehnen eines Plans erscheint eine neue Datei in Obsidian</li><li>[ ] Die Datei enthält Frontmatter und den <code>[[Plannotator Plans]]</code>-Backlink</li></ul><h2 id="frontmatter-und-tags-im-detail" tabindex="-1">Frontmatter und Tags im Detail <a class="header-anchor" href="#frontmatter-und-tags-im-detail" aria-label="Permalink to &quot;Frontmatter und Tags im Detail&quot;">​</a></h2><h3 id="frontmatter-struktur" tabindex="-1">Frontmatter-Struktur <a class="header-anchor" href="#frontmatter-struktur" aria-label="Permalink to &quot;Frontmatter-Struktur&quot;">​</a></h3><p>Jeder gespeicherte Plan enthält die folgenden Frontmatter-Felder:</p><table tabindex="0"><thead><tr><th>Feld</th><th>Beispielwert</th><th>Beschreibung</th></tr></thead><tbody><tr><td><code>created</code></td><td><code>2026-01-24T14:30:00.000Z</code></td><td>Erstellungszeitstempel im ISO 8601-Format</td></tr><tr><td><code>source</code></td><td><code>plannotator</code></td><td>Fester Wert zur Kennzeichnung der Quelle</td></tr><tr><td><code>tags</code></td><td><code>[plan, authentication, typescript]</code></td><td>Automatisch extrahiertes Tag-Array</td></tr></tbody></table><h3 id="regeln-fur-die-tag-generierung" tabindex="-1">Regeln für die Tag-Generierung <a class="header-anchor" href="#regeln-fur-die-tag-generierung" aria-label="Permalink to &quot;Regeln für die Tag-Generierung&quot;">​</a></h3><p>Plannotator verwendet die folgenden Regeln zur automatischen Tag-Extraktion:</p><ol><li><strong>Standard-Tag</strong>: Enthält immer das Tag <code>plannotator</code></li><li><strong>Projektname-Tag</strong>: Wird automatisch aus dem Git-Repository-Namen oder Verzeichnisnamen extrahiert</li><li><strong>Titel-Schlüsselwörter</strong>: Extrahiert bedeutungsvolle Wörter aus der ersten H1-Überschrift (unter Ausschluss gängiger Stoppwörter)</li><li><strong>Codesprachen-Tags</strong>: Werden aus den Sprachkennzeichnungen von Codeblöcken extrahiert (z.B. <code>typescript</code>, <code>sql</code>). Allgemeine Konfigurationssprachen (wie <code>json</code>, <code>yaml</code>, <code>markdown</code>) werden automatisch herausgefiltert.</li></ol><p>Stoppwortliste (werden nicht als Tags verwendet):</p><ul><li><code>the</code>, <code>and</code>, <code>for</code>, <code>with</code>, <code>this</code>, <code>that</code>, <code>from</code>, <code>into</code></li><li><code>plan</code>, <code>implementation</code>, <code>overview</code>, <code>phase</code>, <code>step</code>, <code>steps</code></li></ul><p>Tag-Limit: Maximal 7 Tags, sortiert nach Extraktionsreihenfolge.</p><h3 id="dateinamenformat" tabindex="-1">Dateinamenformat <a class="header-anchor" href="#dateinamenformat" aria-label="Permalink to &quot;Dateinamenformat&quot;">​</a></h3><p>Der Dateiname verwendet ein gut lesbares Format: <code>Title - Jan 2, 2026 2-30pm.md</code></p><table tabindex="0"><thead><tr><th>Teil</th><th>Beispiel</th><th>Beschreibung</th></tr></thead><tbody><tr><td>Titel</td><td><code>User Authentication</code></td><td>Aus H1 extrahiert, auf 50 Zeichen begrenzt</td></tr><tr><td>Datum</td><td><code>Jan 2, 2026</code></td><td>Aktuelles Datum</td></tr><tr><td>Uhrzeit</td><td><code>2-30pm</code></td><td>Aktuelle Uhrzeit (12-Stunden-Format)</td></tr></tbody></table><h3 id="backlink-mechanismus" tabindex="-1">Backlink-Mechanismus <a class="header-anchor" href="#backlink-mechanismus" aria-label="Permalink to &quot;Backlink-Mechanismus&quot;">​</a></h3><p>Am Ende jeder Plandatei wird ein <code>[[Plannotator Plans]]</code>-Link eingefügt. Dieser Backlink dient folgenden Zwecken:</p><ul><li><strong>Wissensgraph-Verbindung</strong>: In der Graph-Ansicht von Obsidian sind alle Pläne mit demselben Knoten verbunden</li><li><strong>Schnelle Navigation</strong>: Durch Klicken auf <code>[[Plannotator Plans]]</code> können Sie eine Indexseite erstellen, die alle gespeicherten Pläne zusammenfasst</li><li><strong>Bidirektionale Links</strong>: Auf der Indexseite können Sie über Backlinks alle Pläne einsehen</li></ul><h2 id="plattformubergreifende-unterstutzung" tabindex="-1">Plattformübergreifende Unterstützung <a class="header-anchor" href="#plattformubergreifende-unterstutzung" aria-label="Permalink to &quot;Plattformübergreifende Unterstützung&quot;">​</a></h2><p>Plannotator erkennt automatisch den Speicherort der Obsidian-Konfigurationsdatei auf verschiedenen Betriebssystemen:</p><table tabindex="0"><thead><tr><th>Betriebssystem</th><th>Konfigurationsdateipfad</th></tr></thead><tbody><tr><td>macOS</td><td><code>~/Library/Application Support/obsidian/obsidian.json</code></td></tr><tr><td>Windows</td><td><code>%APPDATA%\\obsidian/obsidian.json</code></td></tr><tr><td>Linux</td><td><code>~/.config/obsidian/obsidian.json</code></td></tr></tbody></table><p>Falls die automatische Erkennung fehlschlägt, können Sie den Vault-Pfad manuell eingeben.</p><h2 id="fehlerbehebung" tabindex="-1">Fehlerbehebung <a class="header-anchor" href="#fehlerbehebung" aria-label="Permalink to &quot;Fehlerbehebung&quot;">​</a></h2><h3 id="problem-1-vaults-werden-nicht-erkannt" tabindex="-1">Problem 1: Vaults werden nicht erkannt <a class="header-anchor" href="#problem-1-vaults-werden-nicht-erkannt" aria-label="Permalink to &quot;Problem 1: Vaults werden nicht erkannt&quot;">​</a></h3><p><strong>Symptom</strong>: Das Dropdown-Menü zeigt „Detecting...&quot; an, aber keine Ergebnisse</p><p><strong>Ursache</strong>: Die Obsidian-Konfigurationsdatei existiert nicht oder hat ein falsches Format</p><p><strong>Lösung</strong>:</p><ol><li>Stellen Sie sicher, dass Obsidian installiert ist und mindestens einmal geöffnet wurde</li><li>Überprüfen Sie, ob die Konfigurationsdatei existiert (siehe Pfade in der obigen Tabelle)</li><li>Verwenden Sie „Custom path...&quot;, um den Vault-Pfad manuell einzugeben</li></ol><h3 id="problem-2-datei-nach-dem-speichern-nicht-auffindbar" tabindex="-1">Problem 2: Datei nach dem Speichern nicht auffindbar <a class="header-anchor" href="#problem-2-datei-nach-dem-speichern-nicht-auffindbar" aria-label="Permalink to &quot;Problem 2: Datei nach dem Speichern nicht auffindbar&quot;">​</a></h3><p><strong>Symptom</strong>: Nach der Genehmigung eines Plans erscheint keine neue Datei in Obsidian</p><p><strong>Ursache</strong>: Falscher Vault-Pfad oder Obsidian wurde nicht aktualisiert</p><p><strong>Lösung</strong>:</p><ol><li>Überprüfen Sie, ob der Vorschaupfad im Einstellungsfenster korrekt ist</li><li>Klicken Sie in Obsidian auf „Reload vault&quot; oder drücken Sie <code>Cmd+R</code> (macOS) / <code>Ctrl+R</code> (Windows/Linux)</li><li>Überprüfen Sie, ob der richtige Vault ausgewählt ist</li></ol><h3 id="problem-3-dateiname-enthalt-sonderzeichen" tabindex="-1">Problem 3: Dateiname enthält Sonderzeichen <a class="header-anchor" href="#problem-3-dateiname-enthalt-sonderzeichen" aria-label="Permalink to &quot;Problem 3: Dateiname enthält Sonderzeichen&quot;">​</a></h3><p><strong>Symptom</strong>: Im Dateinamen erscheinen <code>_</code> oder andere Ersatzzeichen</p><p><strong>Ursache</strong>: Der Titel enthält Zeichen, die vom Dateisystem nicht unterstützt werden (<code>&lt; &gt; : &quot; / \\ | ? *</code>)</p><p><strong>Lösung</strong>: Dies ist das erwartete Verhalten. Plannotator ersetzt diese Zeichen automatisch, um Dateisystemfehler zu vermeiden.</p><h2 id="zusammenfassung" tabindex="-1">Zusammenfassung <a class="header-anchor" href="#zusammenfassung" aria-label="Permalink to &quot;Zusammenfassung&quot;">​</a></h2><p>Die Obsidian-Integration verbindet Ihren Plan-Review-Workflow nahtlos mit Ihrem Wissensmanagement:</p><ul><li>✅ Automatisches Speichern genehmigter oder abgelehnter Pläne</li><li>✅ Intelligente Tag-Extraktion für einfaches späteres Auffinden</li><li>✅ Frontmatter-Generierung für einheitliches Metadatenformat</li><li>✅ Backlinks hinzufügen, um einen Wissensgraphen aufzubauen</li></ul><p>Nach einmaliger Konfiguration wird jede Überprüfung automatisch archiviert – kein manuelles Kopieren und Einfügen mehr erforderlich.</p><h2 id="vorschau-auf-die-nachste-lektion" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion lernen wir die <strong><a href="./../bear-integration/">Bear-Integration</a></strong>.</p><p>Sie werden lernen:</p><ul><li>Wie Sie Pläne in der Bear-Notiz-App speichern</li><li>Die Unterschiede zwischen Bear- und Obsidian-Integration</li><li>Wie Sie x-callback-url verwenden, um automatisch Notizen zu erstellen</li></ul></blockquote><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken Sie hier, um die Quellcode-Positionen anzuzeigen</strong></summary><blockquote><p>Aktualisiert: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilen</th></tr></thead><tbody><tr><td>Obsidian Vaults erkennen</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L135-L175" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>135-175</td></tr><tr><td>Plan in Obsidian speichern</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L180-L227" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>180-227</td></tr><tr><td>Tags extrahieren</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L34-L74" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>34-74</td></tr><tr><td>Frontmatter generieren</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L81-L89" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>81-89</td></tr><tr><td>Dateinamen generieren</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L111-L127" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>111-127</td></tr><tr><td>Obsidian-Einstellungen speichern</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/obsidian.ts#L36-L43" target="_blank" rel="noreferrer"><code>packages/ui/utils/obsidian.ts</code></a></td><td>36-43</td></tr><tr><td>Settings UI-Komponente</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/Settings.tsx#L387-L491" target="_blank" rel="noreferrer"><code>packages/ui/components/Settings.tsx</code></a></td><td>387-491</td></tr></tbody></table><p><strong>Wichtige Funktionen</strong>:</p><ul><li><code>detectObsidianVaults()</code>: Liest die Obsidian-Konfigurationsdatei und gibt eine Liste verfügbarer Vault-Pfade zurück</li><li><code>saveToObsidian(config)</code>: Speichert den Plan im angegebenen Vault, einschließlich Frontmatter und Backlink</li><li><code>extractTags(markdown)</code>: Extrahiert Tags aus dem Planinhalt (Titel-Schlüsselwörter, Codesprachen, Projektname)</li><li><code>generateFrontmatter(tags)</code>: Generiert den YAML-Frontmatter-String</li><li><code>generateFilename(markdown)</code>: Generiert einen lesbaren Dateinamen</li></ul><p><strong>Geschäftsregeln</strong>:</p><ul><li>Maximal 7 Tags (L73)</li><li>Dateiname auf 50 Zeichen begrenzt (L102)</li><li>Unterstützt plattformübergreifende Erkennung von Konfigurationsdateipfaden (L141-149)</li><li>Erstellt automatisch nicht vorhandene Ordner (L208)</li></ul></details>`,79)])])}const p=n(r,[["render",s]]);export{g as __pageData,p as default};
